INSERT INTO `history` VALUES (91, 'session-1777265103879', 1671403256519078138, 'admin@qq.com', 'assistant', '根据知识库依据，答案如下：\n菜单路径：预约管理 > 预约列表 / 来访管理 > 来访列表\n预约管理模块处理客户的参观预约和来访登记。\n护理等级在哪里配置\n老人入住办理需要哪些步骤\n护理计划怎么创建\n退住办理流程是什么\n预约来访如何登记\n智能床位能查看哪些数据\n账单入账列表在哪里\n知识库暂无依据时应该怎么处理', 'd944ad53-7f84-4e7a-bb51-6af5fe5f241d', 5, 0, 'success', '{\"sources\": [{\"score\": 0.8502, \"reason\": \"重排判断可回答且综合得分较高\", \"chunkId\": \"cf6ab8b7b07d8d821bd09dac2be4a9fb-20\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 预约管理 > 功能入口\\n菜单路径：预约管理 > 预约列表 / 来访管理 > 来访列表\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 预约管理 > 功能入口 菜单路径：预约管理 > 预约列表 / 来访管理 > 来访列表\", \"category\": \"system-manuals\", \"selected\": true, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"预约\", \"来访\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown\": {\"finalScore\": 0.8502, \"rerankScore\": 0.8568080199153506, \"vectorScore\": 0.6870614199742493, \"keywordScore\": 1, \"answerabilityScore\": 0.8872}}, {\"score\": 0.8399, \"reason\": \"重排判断可回答且综合得分较高\", \"chunkId\": \"cf6ab8b7b07d8d821bd09dac2be4a9fb-19\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 预约管理\\n预约管理模块处理客户的参观预约和来访登记。\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 预约管理 预约管理模块处理客户的参观预约和来访登记。\", \"category\": \"system-manuals\", \"selected\": true, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"预约\", \"登记\", \"来访\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown\": {\"finalScore\": 0.8399, \"rerankScore\": 0.8580513165573785, \"vectorScore\": 0.6259709117568608, \"keywordScore\": 1, \"answerabilityScore\": 0.8875}}, {\"score\": 0.7688, \"reason\": \"关键问题词覆盖不足\", \"chunkId\": \"cf6ab8b7b07d8d821bd09dac2be4a9fb-27\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 来访管理 > 主要功能\\n新增来访：登记到院来访客户信息。\\n\\n来访列表：分页查询来访记录，支持按姓名、手机号、状态、类型筛选。\\n\\n编辑来访：修改来访记录信息。\\n\\n取消来访：取消来访登记。\\n\\n删除来访：删除来访记录。\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 来访管理 > 主要功能 新增来访：登记到院来访客户信息。 来访列表：分页查询来访记录，支持按姓名、手机号、状态、类型筛选。 编辑来访：修改来访记录信息。 取消来访：取消来访登记。 删除来访：删除来访记录。\", \