INSERT INTO `history` VALUES (129, 'session-1777362927804', 1671403256519078138, 'admin@qq.com', 'assistant', '智能床位可查看的数据包括：\n1. 床位实时状态：空闲、占用、预约等\n2. 入住老人信息：姓名、年龄、护理等级\n3. 智能设备数据：\n - 床垫压力分布\n - 心率监测数据\n - 呼吸频率\n - 离床报警记录\n - 睡眠质量分析\n4. 护理任务提醒：待执行的护理任务\n5. 历史数据趋势：各项健康指标的变化趋势', '38ca3910-0ed5-4d6d-a2c7-2c362e4ce5ab', 1, 0, 'success', '{\"sources\": [{\"score\": 0.9455, \"reason\": \"重排判断可回答且综合得分较高\", \"chunkId\": \"330cc9eea1035f331dee15310eba75f9-69\", \"content\": \"章节：中州养老系统使用手册 > 常见问题 > 智能床位能查看哪些数据\\n菜单路径：智能床位\\n\\n智能床位可查看的数据包括：\\n1. 床位实时状态：空闲、占用、预约等\\n2. 入住老人信息：姓名、年龄、护理等级\\n3. 智能设备数据：\\n   - 床垫压力分布\\n   - 心率监测数据\\n   - 呼吸频率\\n   - 离床报警记录\\n   - 睡眠质量分析\\n4. 护理任务提醒：待执行的护理任务\\n5. 历史数据趋势：各项健康指标的变化趋势\", \"snippet\": \"章节：中州养老系统使用手册 > 常见问题 > 智能床位能查看哪些数据 菜单路径：智能床位 智能床位可查看的数据包括： 1. 床位实时状态：空闲、占用、预约等 2. 入住老人信息：姓名、年龄、护理等级 3. 智能设备数据： - 床垫压力分布 - 心率监测数据 - 呼吸频率 - 离床报警记录 - 睡眠质量分析 4. 护理任务提醒：待执行的护理任务 5. 历史数据...\", \"category\": \"system-manuals\", \"selected\": true, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"智能床位能查看哪些数据\", \"智能床位\", \"数据\", \"看哪\", \"些数\", \"床位\", \"能床\", \"智能\", \"位能\", \"能查\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown\": {\"finalScore\": 0.9455, \"rerankScore\": 0.9944029511598392, \"vectorScore\": 0.8371900116566002, \"keywordScore\": 1, \"answerabilityScore\": 0.9186}}, {\"score\": 0.6509, \"reason\": \"关键问题词覆盖不足\", \"chunkId\": \"330cc9eea1035f331dee15310eba75f9-16\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 床位管理 > 数据结构\\n系统采用楼层-房间-床位三级结构：\\n- 楼层：包含多个房间\\n- 房间：属于某个楼层，关联房型，包含多个床位\\n- 床位：属于某个房间，有独立状态（空闲、占用等）\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 床位管理 > 数据结构 系统采用楼层-房间-床位三级结构： - 楼层：包含多个房间 - 房间：属于某个楼层，关联房型，包含多个床位 - 床位：属于某个房间，有独立状态（空闲、占用等）\", \"category\": \"system-manuals\", \"selected\": false, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"床位\", \"数据\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown\": {\"finalScore\": 0.6509, \"rerankScore\": 0.7306227188052906, \"vectorScore\": 0.6703822050711239, \"keywordScore\": 1, \"answerabilityScore\": 0.3807}}, {\"score\": 0.6479, \"reason\": \"关键问题词覆盖不足\", \"chunkId\": \"330cc9eea1035f331dee15310eba75f9-15\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 床位管理 > 主要功能\\n楼层管理：添加、编辑、删除楼层信息，查看楼层下所有房间和床位。\\n\\n房间管理：在指定楼层下添加房间，编辑房间信息（房型、面积等），删除空闲房间。\\n\\n床位管理：在房间内添加床位，编辑床位信息，删除空闲床位，查看床位状态。\\n\\n房型设置：管理房型配置，支持启用/禁用房型。\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 床位管理 > 主要功能 楼层管理：添加、编辑、删除楼层信息，查看楼层下所有房间和床位。 房间管理：在指定楼层下添加房间，编辑房间信息（房型、面积等），删除空闲房间。 床位管理：在房间内添加床位，编辑床位信息，删除空闲床位，查看床位状态。 房型设置：管理房型配置，支持启用/禁用房型。\", \"category\": \"system-manuals\", \"selected\": false, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"床位\", \"数据\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown\": {\"finalScore\": 0.6479, \"rerankScore\": 0.7207540426201642, \"vectorScore\": 0.6864781075908586, \"keywordScore\": 0.9912, \"answerabilityScore\": 0.3782}}, {\"score\": 0.5831, \"reason\": \"关键问题词覆盖不足\", \"chunkId\": \"330cc9eea1035f331dee15310eba75f9-13\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 床位管理\\n床位管理模块负责楼层、房间、床位的层级管理和状态维护。\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 床位管理 床位管理模块负责楼层、房间、床位的层级管理和状态维护。\", \"category\": \"system-manuals\", \"selected\": false, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"床位\", \"数据\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown\": {\"finalScore\": 0.5831, \"rerankScore\": 0.7104532972865336, \"vectorScore\": 0.6785084546388123, \"keywordScore\": 0.6596, \"answerabilityScore\": 0.2956}}, {\"score\": 0.5753, \"reason\": \"关键问题词覆盖不足\", \"chunkId\": \"330cc9eea1035f331dee15310eba75f9-5\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 入住管理 > 主要功能\\n发起入住申请：为老人创建入住申请记录，填写老人基本信息、选择楼层房间床位、关联护理等级和合同信息。\\n\\n分页查询：按老人姓名、身份证号查询入住申请列表，支持分页浏览。\\n\\n查看详情：查看入住申请的完整信息，包括老人信息、床位信息、合同详情、护理等级等。\\n\\n文件上传：支持上传入住相关文档，格式支持JPG、JPEG、PNG、PDF，文件大小不超过10MB。\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 入住管理 > 主要功能 发起入住申请：为老人创建入住申请记录，填写老人基本信息、选择楼层房间床位、关联护理等级和合同信息。 分页查询：按老人姓名、身份证号查询入住申请列表，支持分页浏览。 查看详情：查看入住申请的完整信息，包括老人信息、床位信息、合同详情、护理等级等。 文件上传：支持上传入住相关文档，格式支持...\", \"category\": \"system-manuals\", \"selected\": false, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"床位\", \"数据\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown\": {\"finalScore\": 0.5753, \"rerankScore\": 0.5931420611579543, \"vectorScore\": 0.6337043526964277, \"keywordScore\": 1, \"answerabilityScore\": 0.3463}}, {\"score\": 0.499, \"reason\": \"关键问题词覆盖不足\", \"chunkId\": \"330cc9eea1035f331dee15310eba75f9-53\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 智能助手 > 知识库管理\\n知识库管理页面用于监控知识库状态和管理文档索引。\\n\\n功能说明：\\n- 索引状态：展示知识库当前索引状态（可用、重建中、失败、未初始化）\\n- 文档统计：显示文档总数、分片总数、最近索引时间\\n- 文档列表：展示所有已导入知识库的文档，包含标题、分类、来源文件、更新时间、切片数、状态\\n- 失败记录：展示文档导入或索引失败的任务记录\\n- 重建索引：手动触发知识库索引重建\\n- 刷新：刷新页面数据\\n\\n索引状态说明：\\n- 可用：索引正常，可正常问答\\n- 重建中：正在重建索引，期间可能影响问答质量\\n- 失败：索引构建失败，需查看失败记录并处理\\n- 未初始化：知识库尚未导入文档\\n\\n操作流程：\\n重建索引：\\n1. 进入知识库管理页面\\n2. 查看当前索引状态\\n3. 如需更新知识，点击重建索引按钮\\n4. 等待索引重建完成\\n5. 重建完成后刷新页面确认状态\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 智能助手 > 知识库管理 知识库管理页面用于监控知识库状态和管理文档索引。 功能说明： - 索引状态：展示知识库当前索引状态（可用、重建中、失败、未初始化） - 文档统计：显示文档总数、分片总数、最近索引时间 - 文档列表：展示所有已导入知识库的文档，包含标题、分类、来源文件、更新时间、切片数、状态 - 失败...\", \"category\": \"system-manuals\", \"selected\": false, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"数据\", \"智能\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown\": {\"finalScore\": 0.499, \"rerankScore\": 0.4472279754022182, \"vectorScore\": 0.6171049428509576, \"keywordScore\": 1, \"answerabilityScore\": 0.3098}}, {\"score\": 0.4823, \"reason\": \"关键问题词覆盖不足\", \"chunkId\": \"330cc9eea1035f331dee15310eba75f9-51\", \"content\": \"章节：中州养老系统使用手册 > 核心功能模块 > 智能助手 > 功能入口\\n菜单路径：智能助手 > 知识问答 / 知识库管理 / 命中详情\", \"snippet\": \"章节：中州养老系统使用手册 > 核心功能模块 > 智能助手 > 功能入口 菜单路径：智能助手 > 知识问答 / 知识库管理 / 命中详情\", \"category\": \"system-manuals\", \"selected\": false, \"sourceFile\": \"system-manuals/中州养老系统使用手册.md\", \"matchedTerms\": [\"智能\"], \"documentTitle\": \"中州养老系统使用手册\", \"scoreBreakdown