-- ----------------------------
-- Table structure for order
-- ----------------------------
DROP TABLE IF EXISTS `order`;
CREATE TABLE `order`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `trading_order_no` bigint NULL DEFAULT 0 COMMENT '交易系统订单号',
  `payment_status` tinyint NULL DEFAULT NULL COMMENT '付款状态,1.未付 2已付 3已关闭',
  `amount` decimal(32, 2) NULL DEFAULT NULL COMMENT '金额',
  `refund` decimal(12, 2) NULL DEFAULT 0.00 COMMENT '退款金额【付款后，单位：元',
  `is_refund` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '是否有退款：YES，NO',
  `member_id` bigint NULL DEFAULT NULL COMMENT '客户id',
  `project_id` bigint NULL DEFAULT NULL COMMENT '服务项目id',
  `elder_id` bigint NULL DEFAULT NULL COMMENT '服务对象ID',
  `estimated_arrival_time` datetime NULL DEFAULT NULL COMMENT '预计服务时间',
  `mark` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `reason` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '取消原因',
  `status` int NULL DEFAULT NULL COMMENT '订单状态 0待支付 1待执行 2已执行 3已完成 4已关闭 5已退款',
  `create_time` datetime NOT NULL COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `create_by` bigint NULL DEFAULT NULL COMMENT '创建人id',
  `update_by` bigint NULL DEFAULT NULL COMMENT '更新人id',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `view_status` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '是否可见 0可见 1不可见',
  `order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '订单编号',
  `o_create_type` tinyint NULL DEFAULT NULL COMMENT '取消人类型 1前台 2后台',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 332 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '订单' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of order
-- ----------------------------

-- ----------------------------
-- Table structure for pay_channel
-- ----------------------------
DROP TABLE IF EXISTS `pay_channel`;
CREATE TABLE `pay_channel`  (
  `id` bigint NOT NULL COMMENT '主键',
  `channel_name` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '通道名称',
  `channel_label` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '通道唯一标记',
  `domain` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '域名',
  `app_id` varchar(32) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NOT NULL COMMENT '商户appid',
  `public_key` varchar(2000) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NOT NULL COMMENT '支付公钥',
  `merchant_private_key` varchar(2000) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NOT NULL COMMENT '商户私钥',
  `other_config` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '其他配置',
  `encrypt_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'AES混淆密钥',
  `notify_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '回调地址',
  `enable_flag` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '是否有效',
  `enterprise_id` bigint NULL DEFAULT NULL COMMENT '商户ID【系统内部识别使用】',
  `create_time` datetime NOT NULL COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `create_by` bigint NULL DEFAULT NULL COMMENT '创建人id',
  `update_by` bigint NULL DEFAULT NULL COMMENT '更新人id',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '交易渠道表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of pay_channel
-- ----------------------------

-- ----------------------------
-- Table structure for pending_tasks
-- ----------------------------
DROP TABLE IF EXISTS `pending_tasks`;
CREATE TABLE `pending_tasks`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '编号',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '标题',
  `type` tinyint NULL DEFAULT NULL COMMENT '类型（1：退住，2：请假，3：入住）',
  `assignee` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '操作人',
  `assignee_id` bigint NULL DEFAULT NULL COMMENT '操作人id',
  `status` tinyint NULL DEFAULT NULL COMMENT '状态（1：申请中，2:已完成，3:已关闭）',
  `application_time` datetime NULL DEFAULT NULL COMMENT '申请时间',
  `applicat` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '申请人',
  `applicat_id` bigint NULL DEFAULT NULL COMMENT '申请人id',
  `finish_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  `is_handle` tinyint NULL DEFAULT NULL COMMENT '是否处理完成（0：未处理，1：已处理）',
  `create_time` datetime NULL DEFAULT NULL,
  `update_time` datetime NULL DEFAULT NULL,
  `create_by` bigint NULL DEFAULT NULL,
  `update_by` bigint NULL DEFAULT NULL,
  `step_no` int NULL DEFAULT NULL COMMENT '审核步骤（从0开始）',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1137 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '待办任务表' ROW_FORMAT = DYNAMIC;

